    for (int i = n - 2; i >= 0; i--) {
        suffixGCD[i] = gcd(suffixGCD[i + 1], nums[i]);
    }

    for (int i = 0; i <= n - target; i++) {
        int j = (int) (i + target - 1);
        long currentGCD;
        if (i == 0 && j == n - 1) {
            currentGCD = prefixGCD[n - 1];
        } else if (i == 0) {
            currentGCD = suffixGCD[j + 1];
        } else if (j == n - 1) {
            currentGCD = prefixGCD[i - 1];
        } else {
            currentGCD = gcd(prefixGCD[i - 1], suffixGCD[j + 1]);
        }

        if (currentGCD >= 2) {
            return false;
        }
    }

    return true;
}

private static long gcd(long a, long b) {
    while (b != 0) {
        long temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}
