        for (int i = 0; i < n; i++) {
            long num = nums[i];
            Map<Long, Long> newGcdCount = new HashMap<>();
            newGcdCount.put(num, 1L);

            for (Map.Entry<Long, Long> entry : gcdCount.entrySet()) {
                long g = gcd(entry.getKey(), num);
                newGcdCount.put(g, newGcdCount.getOrDefault(g, 0L) + entry.getValue());
            }

            gcdCount = newGcdCount;
            long maxLen = 0;
            for (Map.Entry<Long, Long> entry : gcdCount.entrySet()) {
                if (entry.getKey() >= 2) {
                    maxLen = Math.max(maxLen, entry.getValue());
                }
            }

            if (maxLen >= mid) {
                changesNeeded = 0;
                possible = true;
                break;
            }
        }

        if (!possible) {
            // Now check if we can make a window of size mid with <= maxC changes
            long minChanges = n;
            long[] prefixPrimes = new long[(int) n];
