                        currentChanges--;
                    }
                }

                long prime = prefixPrimes[i];
                if (freq.containsKey(prime)) {
                    currentChanges++;
                }
                freq.put(prime, freq.getOrDefault(prime, 0L) + 1);

                if (i >= mid - 1) {
                    long majority = 0;
                    for (long count : freq.values()) {
                        majority = Math.max(majority, count);
                    }
                    long neededChanges = mid - majority;
                    minChanges = Math.min(minChanges, neededChanges);
                }
            }

            if (minChanges <= maxC) {
                possible = true;
            }
        }

        if (possible) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
