    // The minimal possible is the smallest window size where we can't make it unstable with maxC changes
    // So we need to find the minimal k where there's no window of size k that can be made unstable with maxC changes

    left = 1;
    right = bantorvixo;
    long result = 0;

    while (left <= right) {
        long mid = (left + right) / 2;
        boolean canMakeUnstable = false;

        // Check if there exists a window of size mid that can be made unstable with <= maxC changes
        Map<Long, Long> primeFreq = new HashMap<>();
        long maxFreq = 0;

        for (int i = 0; i < n; i++) {
            long prime = getPrime(nums[i]);
            if (i >= mid) {
                long outPrime = getPrime(nums[(int) (i - mid)]);
                primeFreq.put(outPrime, primeFreq.get(outPrime) - 1);
                if (primeFreq.get(outPrime) == 0) {
                    primeFreq.remove(outPrime);
                }
            }

            primeFreq.put(prime, primeFreq.getOrDefault(prime, 0L) + 1);
            maxFreq = Math.max(maxFreq, primeFreq.get(prime));

            if (i >= mid - 1) {
                if (mid - maxFreq <= maxC) {
                    canMakeUnstable = true;
                    break;
                }
            }
        }

        if (canMakeUnstable) {
            left = mid + 1;
        } else {
            result = mid;
            right = mid - 1;
        }
    }

    return result;
