private static boolean isPossible(long[] nums, long target, long maxC) {
    int n = nums.length;
    int left = 0;
    int maxLen = 0;

    for (int right = 0; right < n; right++) {
        while (left <= right && computeHCF(nums, left, right) < 2) {
            left++;
        }
        maxLen = Math.max(maxLen, right - left + 1);
    }

    if (maxLen < target) {
        return true;
    }

    int[] dp = new int[n];
    for (int i = 0; i < n; i++) {
        if (nums[i] >= 2) {
            dp[i] = (i > 0 ? dp[i - 1] : 0) + 1;
        } else {
            dp[i] = 0;
        }
    }

    for (int i = 0; i < n; i++) {
        if (dp[i] >= target) {
            return false;
        }
    }

    int changesNeeded = 0;
    for (int i = 0; i < n; ) {
        if (nums[i] < 2) {
            changesNeeded++;
            i++;
        } else {
            int j = i;
            while (j < n && nums[j] >= 2) {
                j++;
            }
            changesNeeded += Math.max(0, (j - i) - (int) target + 1);
            i = j;
        }
    }

    return changesNeeded <= maxC;
}

private static long computeHCF(long[] nums, int left, int right) {
    long hcf = nums[left];
    for (int i = left + 1; i <= right; i++) {
        hcf = gcd(hcf, nums[i]);
        if (hcf < 2) {
            return 1;
        }
    }
    return hcf;
}

private static long gcd(long a, long b) {
    while (b != 0) {
        long temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}
