    int n = nums.length;
    Map<Long, Integer> primeCounts = new HashMap<>();
    int left = 0;

    for (int right = 0; right < n; right++) {
        long num = nums[right];
        if (num < 2) {
            primeCounts.clear();
            left = right + 1;
            continue;
        }

        Set<Long> primes = getPrimes(num);
        for (long p : primes) {
            primeCounts.put(p, primeCounts.getOrDefault(p, 0) + 1);
        }

        while (right - left + 1 > len) {
            long leftNum = nums[left];
            Set<Long> leftPrimes = getPrimes(leftNum);
            for (long p : leftPrimes) {
                primeCounts.put(p, primeCounts.get(p) - 1);
                if (primeCounts.get(p) == 0) {
                    primeCounts.remove(p);
                }
            }
            left++;
        }

        if (right - left + 1 == len) {
            if (!primeCounts.isEmpty()) {
                return false;
            }
        }
    }

    return true;
}

private static Set<Long> getPrimes(long num) {
    Set<Long> primes = new HashSet<>();
    if (num < 2) return primes;

    for (long i = 2; i * i <= num; i++) {
        while (num % i == 0) {
            primes.add(i);
            num /= i;
        }
    }
    if (num > 1) {
        primes.add(num);
    }
    return primes;
