private static List<Long> getPrimeFactors(long num) {
    List<Long> factors = new ArrayList<>();
    if (num < 2) return factors;

    for (long i = 2; i * i <= num; i++) {
        while (num % i == 0) {
            factors.add(i);
            num /= i;
        }
    }
    if (num > 1) {
        factors.add(num);
    }
